  1	import * as React from 'react';
  2	import { IRow, ThProps } from '@patternfly/react-table';
  3	import { Button, ButtonVariant, FormSelect, FormSelectOption, TextInput } from '@patternfly/react-core';
  4	import { SimpleTable } from 'components/Table/SimpleTable';
  5	import { KialiIcon } from 'config/KialiIcon';
  6	import { t, useKialiTranslation } from 'utils/I18nUtils';
  7	
  8	type Props = {
  9	  onAddTo: (operation: { [key: string]: string[] }) => void;
 10	};
 11	
 12	const INIT_OPERATION_FIELDS = [
 13	  'hosts',
 14	  'notHosts',
 15	  'ports',
 16	  'notPorts',
 17	  'methods',
 18	  'notMethods',
 19	  'paths',
 20	  'notPaths'
 21	].sort();
 22	
 23	const columns: ThProps[] = [
 24	  {
 25	    title: t('Operation Field'),
 26	    width: 20
 27	  },
 28	  {
 29	    title: t('Values'),
 30	    width: 80
 31	  },
 32	  {
 33	    title: ''
 34	  }
 35	];
 36	
 37	export const OperationBuilder: React.FC<Props> = (props: Props) => {
 38	  const [newOperationField, setNewOperationField] = React.useState<string>(INIT_OPERATION_FIELDS[0]);
 39	  const [newValues, setNewValues] = React.useState<string>('');
 40	  const [operation, setOperation] = React.useState<{ [key: string]: string[] }>({});
 41	  const [operationFields, setOperationFields] = React.useState<string[]>(INIT_OPERATION_FIELDS);
 42	
 43	  const { t } = useKialiTranslation();
 44	
 45	  const onAddNewOperationField = (_event: React.FormEvent, value: string): void => {
 46	    setNewOperationField(value);
 47	  };
 48	
 49	  const onAddNewValues = (_event: React.FormEvent, value: string): void => {
 50	    setNewValues(value);
 51	  };
 52	
 53	  const onAddOperation = (): void => {
 54	    const newOperationFields = [...operationFields];
 55	    const i = operationFields.indexOf(newOperationField);
 56	
 57	    if (i > -1) {
 58	      newOperationFields.splice(i, 1);
 59	    }
 60	
 61	    const newOperation = { ...operation };
 62	    newOperation[newOperationField] = newValues.split(',');
 63	
 64	    setOperation(newOperation);
 65	    setOperationFields(newOperationFields);
 66	    setNewOperationField(newOperationFields[0]);
 67	    setNewValues('');
 68	  };
 69	
 70	  const onAddOperationToList = (): void => {
 71	    const toItem = operation;
 72	
 73	    setOperationFields(INIT_OPERATION_FIELDS);
 74	    setOperation({});
 75	    setNewOperationField(INIT_OPERATION_FIELDS[0]);
 76	    setNewValues('');
 77	
 78	    props.onAddTo(toItem);
 79	  };
 80	
 81	  const onRemoveOperation = (removeOperationField: string): void => {
 82	    let newOperationFields = [...operationFields];
 83	    newOperationFields.push(removeOperationField);
 84	    newOperationFields = newOperationFields.sort();
 85	
 86	    const newOperation = { ...operation };
 87	    delete newOperation[removeOperationField];
 88	
 89	    setOperation(newOperation);
 90	    setOperationFields(newOperationFields);
 91	    setNewOperationField(newOperationFields[0]);
 92	    setNewValues('');
 93	  };
 94	
 95	  const rows = (): IRow[] => {
 96	    const operatorRows = Object.keys(operation).map((operationField, i) => {
 97	      return {
 98	        key: `operationKey_${i}`,
 99	        cells: [
100	          <>{operationField}</>,
101	          <>{operation[operationField].join(',')}</>,
102	          <Button
103	            id="removeOperationBtn"
104	            variant={ButtonVariant.link}
105	            icon={<KialiIcon.Delete />}
106	            onClick={() => onRemoveOperation(operationField)}
107	          />
108	        ]
109	      };
110	    });
111	
112	    if (operationFields.length > 0) {
113	      return operatorRows.concat([
114	        {
115	          key: 'operationKeyNew',
116	          cells: [
117	            <FormSelect
118	              value={newOperationField}
119	              id="addNewOperationField"
120	              name="addNewOperationField"
121	              onChange={onAddNewOperationField}
122	            >
123	              {operationFields.map((option, index) => (
124	                <FormSelectOption isDisabled={false} key={`operation_${index}`} value={option} label={option} />
125	              ))}
126	            </FormSelect>,
127	
128	            <TextInput
129	              value={newValues}
130	              type="text"
131	              id="addNewValues"
132	              key="addNewValues"
133	              aria-describedby={t('Add new operation values')}
134	              name="addNewValues"
135	              onChange={onAddNewValues}
136	            />,
137	            <>
138	              {operationFields.length > 0 && (
139	                <Button variant={ButtonVariant.link} icon={<KialiIcon.AddMore />} onClick={onAddOperation} />
140	              )}
141	            </>
142	          ]
143	        }
144	      ]);
145	    }
146	    return operatorRows;
147	  };
148	
149	  return (
150	    <>
151	      <SimpleTable label={t('Operation Builder')} columns={columns} rows={rows()} />
152	
153	      <Button
154	        variant={ButtonVariant.link}
155	        icon={<KialiIcon.AddMore />}
156	        isDisabled={Object.keys(operation).length === 0}
157	        onClick={onAddOperationToList}
158	      >
159	        {t('Add Operation to To List')}
160	      </Button>
161	    </>
162	  );
163	};

